def solution(a_limit: int = 100, b_limit: int = 100) -> int:
    """
    Returns the number of distinct terms in the sequence a^b
    for 2 <= a <= a_limit and 2 <= b <= b_limit.
    """
    distinct_powers = set()
    for a in range(2, a_limit + 1):
        for b in range(2, b_limit + 1):
            distinct_powers.add(a**b)
    return len(distinct_powers)


